CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, clerk_id TEXT NOT NULL UNIQUE, email TEXT, username TEXT, avatar_url TEXT, subscription_tier TEXT DEFAULT 'free', subscription_ends INTEGER, stripe_customer_id TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS memory_palaces (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), name TEXT NOT NULL, description TEXT, subject TEXT, loci_count INTEGER DEFAULT 0, loci TEXT DEFAULT '[]', image_url TEXT, is_public INTEGER DEFAULT 0, tags TEXT DEFAULT '[]', slug TEXT NOT NULL DEFAULT '', content_hash TEXT, extras TEXT DEFAULT '{}', created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE UNIQUE INDEX IF NOT EXISTS idx_palaces_user_slug ON memory_palaces(user_id, slug);
CREATE TABLE IF NOT EXISTS mnemonic_stories (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), palace_id TEXT REFERENCES memory_palaces(id), title TEXT NOT NULL, content TEXT, subject TEXT, concepts TEXT DEFAULT '[]', narrative_style TEXT DEFAULT 'default', image_urls TEXT DEFAULT '[]', is_public INTEGER DEFAULT 0, tags TEXT DEFAULT '[]', created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS symbols (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), story_id TEXT REFERENCES mnemonic_stories(id), concept TEXT NOT NULL, symbol TEXT NOT NULL, description TEXT, category TEXT, image_url TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS study_sessions (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), subject TEXT NOT NULL, topic TEXT, duration_minutes INTEGER, focus_score INTEGER, notes TEXT, mode TEXT DEFAULT 'focused', completed_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS timetables (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), name TEXT NOT NULL, description TEXT, entries TEXT DEFAULT '[]', is_active INTEGER DEFAULT 1, optimized_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS questions (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), subject TEXT NOT NULL, topic TEXT, question_type TEXT DEFAULT 'mcq', difficulty TEXT DEFAULT 'medium', question_text TEXT NOT NULL, options TEXT, correct_answer TEXT, explanation TEXT, source TEXT DEFAULT 'manual', generation_mode TEXT, tags TEXT DEFAULT '[]', is_mistake INTEGER DEFAULT 0, mistake_count INTEGER DEFAULT 0, last_answered_at INTEGER, last_answer_correct INTEGER, fsrs_stability REAL, fsrs_difficulty REAL, fsrs_state INTEGER DEFAULT 0, fsrs_due INTEGER, fsrs_elapsed_days INTEGER DEFAULT 0, fsrs_scheduled_days INTEGER DEFAULT 0, fsrs_reps INTEGER DEFAULT 0, fsrs_lapses INTEGER DEFAULT 0, fsrs_last_review INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS payments (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), stripe_session_id TEXT, stripe_subscription_id TEXT, stripe_invoice_id TEXT, amount INTEGER, currency TEXT DEFAULT 'hkd', status TEXT DEFAULT 'pending', tier TEXT, interval TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS annotations (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), title TEXT NOT NULL, content TEXT, source_url TEXT, subject TEXT, pass1_summary TEXT, pass2_analysis TEXT, pass3_synthesis TEXT, key_terms TEXT DEFAULT '[]', questions TEXT DEFAULT '[]', tags TEXT DEFAULT '[]', current_pass INTEGER DEFAULT 1, is_complete INTEGER DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS reading_vault (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), title TEXT NOT NULL, original_text TEXT NOT NULL, language TEXT DEFAULT 'chinese', difficulty_level INTEGER, vocabulary TEXT DEFAULT '[]', grammar_notes TEXT, translation TEXT, analysis TEXT, audio_url TEXT, source_url TEXT, tags TEXT DEFAULT '[]', word_count INTEGER, reading_time_minutes INTEGER, is_analyzed INTEGER DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS recall_sessions (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), title TEXT NOT NULL, mode TEXT NOT NULL, subject TEXT, recall_content TEXT, correct_content TEXT, grade REAL, feedback TEXT, concepts_hit TEXT DEFAULT '[]', concepts_missed TEXT DEFAULT '[]', duration_seconds INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS technocratic_audits (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), audit_type TEXT NOT NULL, period_start INTEGER, period_end INTEGER, metrics TEXT DEFAULT '{}', findings TEXT, recommendations TEXT, score REAL, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS methods (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), name TEXT NOT NULL, description TEXT, category TEXT, steps TEXT DEFAULT '[]', effectiveness REAL, usage_count INTEGER DEFAULT 0, is_custom INTEGER DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
